'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { useState, useEffect } from 'react'
import { Search, Menu, X, BookOpen, Headphones, Users, Info, Tag, Mail, Crown } from 'lucide-react'
import { ThemeToggle } from '@/components/shared/theme-toggle'
import { GradientLogo } from './logo'

const NAV = [
  { href: '/articles', label: 'Bài viết', Icon: BookOpen },
  { href: '/music', label: 'Âm nhạc', Icon: Headphones },
  { href: '/study', label: 'Học live', Icon: Users },
  { href: '/about', label: 'Giới thiệu', Icon: Info },
  { href: '/tags', label: 'Tags', Icon: Tag },
  { href: '/contact', label: 'Liên hệ', Icon: Mail },
  { href: '/premium', label: 'Premium', Icon: Crown },
]

export function Header() {
  const pathname = usePathname()
  const [mounted, setMounted] = useState(false)
  const [mobileOpen, setMobileOpen] = useState(false)

  useEffect(() => {
    setMounted(true)
    // Close mobile nav on route change
    setMobileOpen(false)
  }, [pathname])

  // Close mobile nav on resize
  useEffect(() => {
    const onResize = () => {
      if (window.innerWidth >= 768) setMobileOpen(false)
    }
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [])

  return (
    <>
      <header className="sticky top-0 z-50 w-full">
        {/* Frosted glass bg */}
        <div className="absolute inset-0 bg-background/80 backdrop-blur-xl border-b border-white/[0.06]" />

        <div className="relative">
          <div className="container flex h-14 items-center justify-between">
            {/* Logo */}
            <Link href="/" className="flex items-center gap-2.5 group">
              <GradientLogo size="sm" />
            </Link>

            {/* Desktop Nav */}
            <nav className="hidden md:flex items-center gap-1">
              {NAV.map((item) => {
                const isActive = pathname?.startsWith(item.href)
                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`relative px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200
                      ${isActive
                        ? 'text-foreground bg-white/[0.06]'
                        : 'text-muted-foreground hover:text-foreground hover:bg-white/[0.04]'
                      }`}
                  >
                    {item.label}
                  </Link>
                )
              })}
            </nav>

            {/* Right side */}
            <div className="flex items-center gap-1">
              {/* Search */}
              <Link
                href="/search"
                className="hidden sm:flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs text-muted-foreground hover:text-foreground hover:bg-white/[0.04] transition-all duration-200 border border-transparent hover:border-white/10"
              >
                <Search className="h-3.5 w-3.5" />
                <span className="hidden lg:inline">Tìm kiếm</span>
                <kbd className="hidden lg:inline px-1.5 py-0.5 rounded bg-white/5 text-[10px] font-mono">⌘K</kbd>
              </Link>
              <Link
                href="/search"
                className="sm:hidden p-2 rounded-lg text-muted-foreground hover:text-foreground hover:bg-white/[0.04] transition-all"
              >
                <Search className="h-4 w-4" />
              </Link>

              {/* Theme */}
              {mounted && <ThemeToggle />}

              {/* Mobile menu */}
              <button
                className="md:hidden p-2 rounded-lg text-muted-foreground hover:text-foreground hover:bg-white/[0.04] transition-all"
                onClick={() => setMobileOpen(!mobileOpen)}
                aria-label="Menu"
              >
                {mobileOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
              </button>
            </div>
          </div>

          {/* Mobile nav */}
          <div
            className={`md:hidden border-t border-white/[0.06] bg-background/95 backdrop-blur-xl transition-all duration-300 overflow-hidden ${
              mobileOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
            }`}
          >
            <nav className="container py-3 flex flex-col gap-1">
              {NAV.map((item) => {
                const isActive = pathname?.startsWith(item.href)
                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-200
                      ${isActive
                        ? 'bg-white/[0.06] text-foreground'
                        : 'text-muted-foreground hover:bg-white/[0.04] hover:text-foreground'
                      }`}
                  >
                    <item.Icon className="h-4 w-4" />
                    {item.label}
                  </Link>
                )
              })}
            </nav>
          </div>
        </div>
      </header>
    </>
  )
}

